import os
from google.cloud import storage
from tensorflow_model_analysis import evaluator
from keras.models import load_model

# Function to download latest model from cloud storage bucket
def get_latest_model():
    # Parse the GCS path and split it into bucket name and blob prefix/path
    gcs_bucket, gcs_prefix = os.getenv('MODEL_PATH').split('/', 1)
    
    # Initialize Google Cloud Storage client
    storage_client = storage.Client()
    bucket = storage_client.get_bucket(gcs_bucket)

    # Get all blobs in the provided GCS path
    model_blobs = [blob for blob in bucket.list_blobs(prefix=gcs_prefix)]
    
    if not model_blobs:
        raise Exception('No models found on Google Cloud Storage')
        
    # Get latest model by sorting all blobs based on their creation time and take the last one
    latest_model = sorted(model_blobs, key=lambda x:x.time_created)[-1]
    
    # Create a temporary file path for downloading the blob
    temp_file_path = f"/tmp/{latest_model.name}"
    latest_model.download_to_filename(temp_file_path)
    
    return load_model(temp_file_path)

# Load the latest model on startup
MODEL = get_latest_model()